input.command:
# More careful duplicate pair counting: group by hash, count groups with >1 file
find uploads/project_files/ -type f -exec md5sum {} \; | sort | awk '
{
  hash=$1; file=$2;
  files[hash] = (hash in files) ? files[hash] "\n" file : file;
  count[hash]++
}
END {
  total_pairs=0;
  for (h in count) {
    if (count[h] > 1) {
      n = count[h];
      # number of pairs from n files = n*(n-1)/2
      pairs = n*(n-1)/2;
      total_pairs += pairs;
      print "Hash: " h " (" n " files, " pairs " pairs):";
      print files[h];
      print "";
    }
  }
  print "Total duplicate pairs: " total_pairs;
}'

